insert into curriculum.course_version_graphemes (
  course_version_id,
  grapheme_id,
  romanization,
  pronunciation_hint,
  mnemonic,
  position,
  pedagogical_group_key,
  pedagogical_group_label,
  details,
  tags
)
values
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '155d0198-aac0-5a9d-a8ab-fb839ccab4f9'::uuid, 'm', 'm as in "mother"', 'Two rounded humps make an easy M shape you can spot quickly in common words.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'f9127074-00ba-5295-aac0-01022b890b89'::uuid, 'aa', 'long "aa" as in "father"', 'A tall trailing line stretches the sound to the right, just like the long vowel it marks.', 'right', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '0323b564-2380-5449-aa92-cc5f6772a1a0'::uuid, 'g/k', 'hard g/k sound; final ก closes like "k"', 'A compact hook feels clipped and firm, which matches the tight stop you hear at the end of มาก.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '4cd66937-cf81-571b-ae18-6ae1055dd3ae'::uuid, 'd/t', 'd as in "dog" at the start; clipped t at the end', 'The small domed shape feels grounded and steady, like the reliable d sound at the start of ดี.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'ee1f3cf4-8315-510e-a613-dfc5ec42d2f5'::uuid, 'ii', 'long "ee" as in "see"', 'The long upper stroke sits above the consonant and holds the sound a little longer.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '02613447-13c2-5348-aad7-857e5e6ae103'::uuid, 'n', 'n as in "no"', 'The smooth loop ends softly, which matches the easy n sound it gives you in common words.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553'::uuid, 'i', 'short "i" as in "sit"', 'The tiny mark above is quick and short, just like the clipped i sound it signals.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '5b347f02-b891-5f29-ad35-11da91e7b87c'::uuid, 't', 't as in "stop" (unaspirated)', 'The little turtle-like shape is compact and steady, which matches the plain unaspirated t sound.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '50ada581-79e7-5549-a9a8-77693569d9b8'::uuid, 'l', 'l as in "love"', 'The looping lower line gives you an easy L that opens up many market and place words.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'dddb2e02-9aa3-5dde-a2ab-25524fc96559'::uuid, 'b/p', 'b as in "bat" at the start; clipped p at the end', 'The open bowl shape makes บ easy to spot at the start of short, useful words like บิน and บิล.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '1684cb46-8524-51a4-ad84-8dd2fe3b46be'::uuid, 'ae', 'long "ae" as in the vowel of "care"', 'The doubled left-side shape sits in front of the consonant, warning you to scan left before you pronounce.', 'left', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '13e7c7cd-283c-5d0b-a9cc-ce5b3831e495'::uuid, 'mai ek', 'first tone mark written above the consonant', 'The short falling tick leans downward like a small tone reminder dropped above the syllable.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '76e47267-9161-5fee-a1e7-f698d88554f8'::uuid, 'r', 'r as in "run" at the start; n at the end in some words', 'The flowing curve looks like it wants to roll forward, which helps you remember its quick initial r sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '56d6049c-5c20-5436-a5d0-37ea5d73fe05'::uuid, 'mai tho', 'second tone mark written above the consonant', 'The heavier mark sits above the consonant like a second, stronger tone cue.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '9593d6a6-13bb-563d-a33d-b01dd74e3528'::uuid, 'ch', 'ch as in "check"', 'The open top and downward turn give ช a distinct profile that is easy to separate from ส once you have seen it a few times.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'a57ca296-4754-50f0-aad0-9856fff5c81d'::uuid, 'u', 'short "u" as in "put"', 'The small mark tucked below the consonant keeps the sound short and tight.', 'below', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'ae26196d-7a39-57e3-a8c4-061567bf9167'::uuid, 's', 's as in "sun"', 'The tall curve with a pointed finish feels sharp, which matches the crisp s sound at the start of words.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'd9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad'::uuid, 'kh', 'kh with a puff of air, like the start of "khaki"', 'It looks like a more open cousin of ก, which helps you remember it is the airy high-class kh version.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '5e1b543b-6be0-5279-a812-4ec61ce2b1dc'::uuid, 'w', 'w as in "water"; can help form vowel glides', 'The curling shape feels like a small wave, which makes the w sound easy to picture.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '98079396-6adf-5409-a63c-121764a3840e'::uuid, 'h', 'h as in "hello"; often used as a leading tone helper', 'The tall jar-like shape is easy to remember, and in many useful words it quietly sets up the tone of the consonant after it.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '6cbd6547-63c8-52cd-a2e5-378aa42e3e46'::uuid, 'uu', 'long "oo" as in "food"', 'The long lower loop hangs below the consonant and keeps the oo sound going.', 'below', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'd6388a97-b0cb-5594-af90-48fd4c770e0f'::uuid, 'silent carrier', 'placeholder consonant used when a syllable begins with a vowel sound', 'The empty circle looks like an open placeholder, which is exactly what it does when Thai needs a consonant slot for a vowel.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'da8975d2-f60a-59f9-a1d2-f55df44b6bfa'::uuid, 'ph', 'ph with a puff of air, like the start of "photo" without the f sound', 'Its tall, open shape makes it feel like an airy cousin of บ, which helps you remember the aspirated ph sound.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '6655bad5-f432-5868-aa67-e7247253802f'::uuid, 'a', 'short "a" as in "cut"', 'The small cap above the consonant keeps the vowel short and quick.', 'above', null, null, '{}'::jsonb, array[]::text[]);

