  ('2b08fe9f-7330-561e-a49c-f0e155dbdd71'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'b248fb0f-5294-57b4-af76-9938cb3f905c'::uuid, 'maak', 1, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"b248fb0f-5294-57b4-af76-9938cb3f905c","slug":"maak","lessonOrdinal":1,"stage":1,"title":"มาก — Your First High-Payoff Word","anchor":{"id":"1369806e-4ea8-5225-af4b-53d528e72fd4","slug":"maak","text":"มาก","meaning":"very / a lot","pronunciation":"mâak","categoryKey":"daily","contextNote":"You''ll hear and read มาก everywhere: ดีมาก (very good), เผ็ดมาก (very spicy), and discount copy that promises a lot.","segments":[{"text":"มา","sound":"maa"},{"text":"ก","sound":"k"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"c3faa381-054e-5dd0-a64b-fe084d0afe2e","key":"word-0e21-0e32","text":"มา","meaning":"to come","pronunciation":"maa","categoryKey":"daily","contextNote":"A basic movement verb you will hear in invitations, directions, and casual conversation.","segments":[{"text":"มา","sound":"maa"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"c8d1b913-736c-5dcd-a387-f779532f980e","key":"word-0e01-0e32","text":"กา","meaning":"crow","pronunciation":"gaa","categoryKey":"daily","contextNote":"A simple real word that reuses the กา frame with no extra letters added.","segments":[{"text":"กา","sound":"gaa"}],"metadata":{}}}],"newGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"Two rounded humps make an easy M shape you can spot quickly in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"A tall trailing line stretches the sound to the right, just like the long vowel it marks.","position":"right","details":{},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"A compact hook feels clipped and firm, which matches the tight stop you hear at the end of มาก.","position":"standalone","details":{"class":"mid"},"tags":[]}],"reviewGraphemes":[],"rules":[{"id":"671ddf5e-f429-5a7b-a9a1-f88d61020189","key":"long-aa-right","name":"Long า Stretches Right","shortDescription":"า is written after the consonant and gives you a long aa sound","explanation":"Thai often places vowels around a consonant instead of in a straight line like English. The long vowel า sits to the right of the consonant and stretches the syllable into a clear aa sound.","examples":[{"text":"มา = maa"},{"text":"กา = gaa"},{"text":"มาก = mâak"}]},{"id":"884e5d37-78f3-5c0d-abda-be4ea9b3b8a5","key":"final-k-stop","name":"Final ก Ends in a Stop","shortDescription":"At the end of a syllable, ก closes sharply as a k sound","explanation":"Thai final consonants are often clipped. In มาก, the last ก does not open into a full English g. It closes the syllable with a short unreleased k sound.","examples":[{"text":"มาก = mâak"},{"text":"นก = nók"}]}],"drills":[{"id":"b0af3b43-477d-5797-a482-fc941bb4fbbb","key":"maak-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"m\" sound?","payload":{},"options":[{"text":"ก"},{"text":"ม","isCorrect":true},{"text":"น"},{"text":"ด"}]},{"id":"a0aec10d-b933-52ac-ae60-d65d2f0db0a4","key":"maak-drill-02-recognize","type":"recognize","prompt":"Which symbol makes the long \"aa\" sound?","payload":{},"options":[{"text":"า","isCorrect":true},{"text":"ิ"},{"text":"ี"},{"text":"ั"}]},{"id":"b5470778-c016-50d4-a379-30ba09788aae","key":"maak-drill-03-match","type":"match","prompt":"What does มาก mean?","payload":{},"options":[{"text":"mother"},{"text":"very / a lot","isCorrect":true},{"text":"shop"},{"text":"rice"}]},{"id":"d6132d4b-1e57-5b24-a79c-d02969f8deab","key":"maak-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"very / a lot\"?","payload":{},"options":[{"text":"มาก","isCorrect":true},{"text":"กาม"},{"text":"มกา"},{"text":"ดาก"}]},{"id":"cb5ae9af-f16f-5910-a61b-6723a6b8426c","key":"maak-drill-05-sound","type":"sound","prompt":"How does the final ก sound in มาก?","payload":{},"options":[{"text":"m"},{"text":"k","isCorrect":true},{"text":"g"},{"text":"n"}]}]}}'::jsonb, 'd02952cd495547b76fad84bcf08337adcb8bba8a728d3e2954c9310bf0d939e2', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('2858cfe0-23c6-5ef7-ab75-58205949476e'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '4497309f-83d5-5cfd-ae20-98d182c44e7a'::uuid, 'dii', 2, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"4497309f-83d5-5cfd-ae20-98d182c44e7a","slug":"dii","lessonOrdinal":2,"stage":1,"title":"ดี — A Core Word for Good Things","anchor":{"id":"134aa101-deb6-53f4-ab45-73b08ff1f542","slug":"dii","text":"ดี","meaning":"good","pronunciation":"dii","categoryKey":"daily","contextNote":"You''ll see ดี inside greetings, reviews, and product copy. It is one of the most reusable positive words in beginner Thai.","segments":[{"text":"ดี","sound":"dii"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"d0ef507d-f79d-5a6e-af15-15389b449c25","key":"word-0e21-0e35","text":"มี","meaning":"to have","pronunciation":"mii","categoryKey":"daily","contextNote":"A core possession verb that appears constantly in speech and signage.","segments":[{"text":"มี","sound":"mii"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"f932c1d2-de4f-5a71-a5c9-aa0acbd6f665","key":"word-0e14-0e35-0e21-0e32-0e01","text":"ดีมาก","meaning":"very good","pronunciation":"dii maak","categoryKey":"daily","contextNote":"A common praise phrase that combines the first two lessons into one useful chunk.","segments":[{"text":"ดี","sound":"dii"},{"text":"มาก","sound":"maak"}],"metadata":{}}}],"newGraphemes":[{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"The small domed shape feels grounded and steady, like the reliable d sound at the start of ดี.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"The long upper stroke sits above the consonant and holds the sound a little longer.","position":"above","details":{},"tags":[]}],"reviewGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"Two rounded humps make an easy M shape you can spot quickly in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"A tall trailing line stretches the sound to the right, just like the long vowel it marks.","position":"right","details":{},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"A compact hook feels clipped and firm, which matches the tight stop you hear at the end of มาก.","position":"standalone","details":{"class":"mid"},"tags":[]}],"rules":[{"id":"08d94ec2-a20e-5de1-a856-70fd4d44ffe2","key":"long-ii-above","name":"Long ี Sits Above","shortDescription":"ี is written above the consonant and gives you a long ee sound","explanation":"Thai vowels are often placed above, below, or around the consonant. In ดี, the consonant comes first and the long vowel ี sits above it, so you read ด then stretch into ee.","examples":[{"text":"ดี = dii"},{"text":"มี = mii"}]},{"id":"6d95fd8f-f8f2-57a9-a0e0-6895baa2f935","key":"initial-d-sound","name":"Initial ด Starts Cleanly","shortDescription":"At the start of a syllable, ด gives you a plain d sound","explanation":"Thai consonants can behave differently at the start and the end of a syllable. In ดี, ด is initial, so you read it as a straightforward d sound before the vowel.","examples":[{"text":"ดี = dii"},{"text":"ดา = daa"}]}],"drills":[{"id":"e8605038-8125-5bf0-a42d-a92a76a6065d","key":"dii-drill-01-recognize","type":"recognize","prompt":"Which letter starts with the \"d\" sound?","payload":{},"options":[{"text":"ก"},{"text":"ด","isCorrect":true},{"text":"ม"},{"text":"น"}]},{"id":"c511cbcf-61d9-5c02-a71c-24ca1cfd5e33","key":"dii-drill-02-recognize","type":"recognize","prompt":"Which vowel gives the long \"ee\" sound?","payload":{},"options":[{"text":"ี","isCorrect":true},{"text":"า"},{"text":"ิ"},{"text":"ั"}]},{"id":"44769f12-1ed6-5a6d-afa4-1279fd796379","key":"dii-drill-03-match","type":"match","prompt":"What does ดี mean?","payload":{},"options":[{"text":"good","isCorrect":true},{"text":"road"},{"text":"eat"},{"text":"shop"}]},{"id":"0917c93d-dc41-5020-af12-5b2ec5e09d5d","key":"dii-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"good\"?","payload":{},"options":[{"text":"ดี","isCorrect":true},{"text":"ดิ"},{"text":"ดา"},{"text":"มี"}]},{"id":"a33c2908-8601-5a15-aa02-1d63eeadeb59","key":"dii-drill-05-sound","type":"sound","prompt":"In ดี, where is the vowel written?","payload":{},"options":[{"text":"before the consonant"},{"text":"after the consonant"},{"text":"above the consonant","isCorrect":true},{"text":"below the consonant"}]}]}}'::jsonb, 'a931a1c4d77bc69ce360d9594fde1e552d6e38de0c81e91dd7038bfd808d8013', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('9fd4f5c2-b819-551c-ad9a-c00d4ba7b65d'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '3be425cd-ea3e-5f8a-ab88-b1efae8eb80f'::uuid, 'gin', 3, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"3be425cd-ea3e-5f8a-ab88-b1efae8eb80f","slug":"gin","lessonOrdinal":3,"stage":1,"title":"กิน — The Everyday Food Verb","anchor":{"id":"9aa0d234-007d-5705-abe6-013ec5322296","slug":"gin","text":"กิน","meaning":"to eat","pronunciation":"gin","categoryKey":"food","contextNote":"กิน appears everywhere in daily life, from restaurant invitations to questions about what you want to eat.","segments":[{"text":"กิ","sound":"gi"},{"text":"น","sound":"n"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"142df77a-2c8f-5948-af3f-26e5778ff982","key":"word-0e14-0e34-0e19","text":"ดิน","meaning":"soil / earth","pronunciation":"din","categoryKey":"daily","segments":[{"text":"ดิ","sound":"di"},{"text":"น","sound":"n"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"2fb0d7d0-e813-5ed3-a01c-11e7b9cb22cd","key":"word-0e21-0e35-0e14","text":"มีด","meaning":"knife","pronunciation":"miit","categoryKey":"food","contextNote":"A practical kitchen word that reinforces the long ee vowel plus a clipped final stop.","segments":[{"text":"มี","sound":"mii"},{"text":"ด","sound":"t"}],"metadata":{}}}],"newGraphemes":[{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"The smooth loop ends softly, which matches the easy n sound it gives you in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"The tiny mark above is quick and short, just like the clipped i sound it signals.","position":"above","details":{},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"A compact hook feels clipped and firm, which matches the tight stop you hear at the end of มาก.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"The small domed shape feels grounded and steady, like the reliable d sound at the start of ดี.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"The long upper stroke sits above the consonant and holds the sound a little longer.","position":"above","details":{},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"Two rounded humps make an easy M shape you can spot quickly in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"A tall trailing line stretches the sound to the right, just like the long vowel it marks.","position":"right","details":{},"tags":[]}],"rules":[{"id":"90dd223e-c255-5285-a129-360e6205288e","key":"short-i-above","name":"Short ิ Sits Above","shortDescription":"The short i vowel appears above the consonant you read first","explanation":"Thai often asks you to scan above the line as you read. In กิน, the consonant ก comes first and the short vowel ิ is written above it, giving you gi before the final consonant closes the syllable.","examples":[{"text":"กิน = gin"},{"text":"บิน = bin"}]},{"id":"23dac35f-4b61-566e-a6f9-3ba53bd27a9d","key":"final-n-stays-n","name":"Final น Stays N","shortDescription":"At the end of a syllable, น keeps a clear n sound","explanation":"Not every Thai final consonant gets clipped into a stop. Final น stays nasal and easy to hear, so กิน closes with a clear n sound.","examples":[{"text":"กิน = gin"},{"text":"ดิน = din"}]}],"drills":[{"id":"039886d4-14ad-5d4d-a3b4-b8b5dcacec12","key":"gin-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"n\" sound?","payload":{},"options":[{"text":"ก"},{"text":"น","isCorrect":true},{"text":"ด"},{"text":"ม"}]},{"id":"972fb085-b457-5749-a79c-437d4a4536ec","key":"gin-drill-02-recognize","type":"recognize","prompt":"Which vowel gives the short \"i\" sound?","payload":{},"options":[{"text":"ิ","isCorrect":true},{"text":"ี"},{"text":"า"},{"text":"ั"}]},{"id":"7a6c6175-e8ba-5554-adc7-26bebbdd137e","key":"gin-drill-03-match","type":"match","prompt":"What does กิน mean?","payload":{},"options":[{"text":"to eat","isCorrect":true},{"text":"market"},{"text":"ten"},{"text":"fresh"}]},{"id":"9e64189d-5baf-5d61-a29d-2f09f206301d","key":"gin-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"to eat\"?","payload":{},"options":[{"text":"กิน","isCorrect":true},{"text":"กีน"},{"text":"นิก"},{"text":"มิน"}]},{"id":"266b3b73-cd8c-59fc-a698-3e9422669870","key":"gin-drill-05-sound","type":"sound","prompt":"How do you read the end of กิน?","payload":{},"options":[{"text":"gii"},{"text":"gin","isCorrect":true},{"text":"git"},{"text":"gim"}]}]}}'::jsonb, '9d7fedb62d42aeb8f746135cacae70c844dda3d36bbd842e7fd0316482409fb5', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('aa04e55f-f9d0-5f1c-aa13-4dfdf4170fc0'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '4de66997-87a5-56cb-a66f-7b2cce6228ed'::uuid, 'talat', 4, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"4de66997-87a5-56cb-a66f-7b2cce6228ed","slug":"talat","lessonOrdinal":4,"stage":2,"title":"ตลาด — Read the Market Sign","anchor":{"id":"e2ffdcfe-2699-53cb-aa90-ef775738a0b3","slug":"talat","text":"ตลาด","meaning":"market","pronunciation":"tà-làat","categoryKey":"place","contextNote":"Markets are everywhere in Thailand. You''ll see ตลาด on signs for night markets, floating markets, and neighborhood markets.","segments":[{"text":"ตล","sound":"tà-l"},{"text":"า","sound":"aa"},{"text":"ด","sound":"t"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"ce9a0864-6fa5-5db8-aa3f-620547a527ab","key":"word-0e15-0e32","text":"ตา","meaning":"eye","pronunciation":"taa","categoryKey":"daily","segments":[{"text":"ตา","sound":"taa"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"1703a344-4f0d-52f3-ad00-540b407562b1","key":"word-0e25-0e32-0e19","text":"ลาน","meaning":"courtyard / open yard","pronunciation":"laan","categoryKey":"place","segments":[{"text":"ลา","sound":"laa"},{"text":"น","sound":"n"}],"metadata":{}}}],"newGraphemes":[{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"The little turtle-like shape is compact and steady, which matches the plain unaspirated t sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"50ada581-79e7-5549-a9a8-77693569d9b8","text":"ล","kind":"consonant","romanization":"l","pronunciationHint":"l as in \"love\"","mnemonic":"The looping lower line gives you an easy L that opens up many market and place words.","position":"standalone","details":{"class":"low"},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"A compact hook feels clipped and firm, which matches the tight stop you hear at the end of มาก.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"Two rounded humps make an easy M shape you can spot quickly in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"A tall trailing line stretches the sound to the right, just like the long vowel it marks.","position":"right","details":{},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"The small domed shape feels grounded and steady, like the reliable d sound at the start of ดี.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"The smooth loop ends softly, which matches the easy n sound it gives you in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"The tiny mark above is quick and short, just like the clipped i sound it signals.","position":"above","details":{},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"The long upper stroke sits above the consonant and holds the sound a little longer.","position":"above","details":{},"tags":[]}],"rules":[{"id":"b87f5a0a-c8ed-581b-a6ec-928cce42fde3","key":"hidden-vowel-market","name":"Hidden Short \"a\" Vowel","shortDescription":"When two consonants can''t blend, a short \"a\" hides between them","explanation":"In Thai, when two consonants appear next to each other but can''t form a natural cluster, a short \"a\" sound is inserted between them. In ตลาด, the ต and ล can''t blend, so you say \"tà-làat\" not \"tlàat\". This hidden vowel is never written.","examples":[{"text":"ตล = tà-l (hidden \"a\" between ต and ล)"},{"text":"ถนน = thà-nǒn (hidden \"a\" between ถ and น)"}]},{"id":"06f3f841-d7df-5644-a11e-3c5cdebae18c","key":"final-stop-market","name":"Final Consonants are Stopped","shortDescription":"Consonants at the end of a syllable are \"swallowed\"","explanation":"When ด appears at the end of a word, it doesn''t make a full \"d\" sound. Instead, your tongue touches the roof of your mouth but you don''t release it. This is why ตลาด sounds like \"tà-làat\" and not \"tà-làad\".","examples":[{"text":"ตลาด = tà-làat"},{"text":"หมด = mòt"}]}],"drills":[{"id":"02ce9efb-92b9-5876-aef7-7cab864cfe66","key":"talat-drill-01-recognize","type":"recognize","prompt":"Which letter makes the plain \"t\" sound?","payload":{},"options":[{"text":"ถ"},{"text":"ต","isCorrect":true},{"text":"ด"},{"text":"ล"}]},{"id":"8692dc1d-2f3e-5efd-a5d4-b0019e801fa2","key":"talat-drill-02-recognize","type":"recognize","prompt":"Which letter makes the \"l\" sound?","payload":{},"options":[{"text":"ม"},{"text":"น"},{"text":"ล","isCorrect":true},{"text":"ก"}]},{"id":"0ef86fb7-0bfe-50c2-a601-f21c887e9815","key":"talat-drill-03-match","type":"match","prompt":"What does ตลาด mean?","payload":{},"options":[{"text":"road"},{"text":"market","isCorrect":true},{"text":"mother"},{"text":"airport"}]},{"id":"98fee299-f831-5c87-ae8f-1432c5119075","key":"talat-drill-04-sound","type":"sound","prompt":"Why is there an \"a\" between ต and ล in ตลาด?","payload":{},"options":[{"text":"Because it is written but invisible"},{"text":"Because Thai inserts a short \"a\" when the consonants do not blend naturally","isCorrect":true},{"text":"Because the tone mark creates it"},{"text":"Because ล always starts with a vowel"}]},{"id":"67fb27d1-1746-5a08-aec8-8dac1b69edad","key":"talat-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"market\"?","payload":{},"options":[{"text":"ตลาด","isCorrect":true},{"text":"ตาลด"},{"text":"ลาดต"},{"text":"ดาลต"}]}]}}'::jsonb, '3bb83f6dd5b8b5d3a7ade5c2126eaa21fffb9613c10adaf2737e95709cb6e3b6', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('4cd0ebf5-d946-51b1-af06-0011cef5d048'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '0afff15b-0b20-53d3-ae86-21d3fe37de52'::uuid, 'bin', 5, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"0afff15b-0b20-53d3-ae86-21d3fe37de52","slug":"bin","lessonOrdinal":5,"stage":2,"title":"บิน — Reuse the -ิน Pattern","anchor":{"id":"689621ae-0664-5f67-abdf-69572aa9cd01","slug":"bin","text":"บิน","meaning":"to fly","pronunciation":"bin","categoryKey":"transport","contextNote":"บิน appears in airport language, travel offers, and casual talk about planes and trips. It also helps you see how reusable the -ิน frame is.","segments":[{"text":"บิ","sound":"bi"},{"text":"น","sound":"n"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"43928d42-5009-56d4-aeaf-c3d01a2bffd0","key":"word-0e1a-0e32-0e19","text":"บาน","meaning":"to bloom / open out","pronunciation":"baan","categoryKey":"daily","segments":[{"text":"บา","sound":"baa"},{"text":"น","sound":"n"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"82cad9f2-05d2-56aa-a194-fa4c6dfe85ff","key":"word-0e1a-0e35-0e1a","text":"บีบ","meaning":"to squeeze","pronunciation":"biip","categoryKey":"daily","segments":[{"text":"บี","sound":"bii"},{"text":"บ","sound":"p"}],"metadata":{}}}],"newGraphemes":[{"id":"dddb2e02-9aa3-5dde-a2ab-25524fc96559","text":"บ","kind":"consonant","romanization":"b/p","pronunciationHint":"b as in \"bat\" at the start; clipped p at the end","mnemonic":"The open bowl shape makes บ easy to spot at the start of short, useful words like บิน and บิล.","position":"standalone","details":{"class":"mid"},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"A compact hook feels clipped and firm, which matches the tight stop you hear at the end of มาก.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"The smooth loop ends softly, which matches the easy n sound it gives you in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"The tiny mark above is quick and short, just like the clipped i sound it signals.","position":"above","details":{},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"The small domed shape feels grounded and steady, like the reliable d sound at the start of ดี.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"The little turtle-like shape is compact and steady, which matches the plain unaspirated t sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"50ada581-79e7-5549-a9a8-77693569d9b8","text":"ล","kind":"consonant","romanization":"l","pronunciationHint":"l as in \"love\"","mnemonic":"The looping lower line gives you an easy L that opens up many market and place words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"A tall trailing line stretches the sound to the right, just like the long vowel it marks.","position":"right","details":{},"tags":[]}],"rules":[{"id":"6346557e-a6a4-5dac-adcd-4617cd7f09a1","key":"initial-b-sound","name":"Initial บ Starts With B","shortDescription":"At the start of a syllable, บ gives you a plain b sound","explanation":"Thai consonants often shift between initial and final positions. In บิน, บ comes first, so it sounds like a clean b before the short vowel and final consonant close the word.","examples":[{"text":"บิน = bin"},{"text":"บา = baa"}]},{"id":"30f160d3-cbb7-5e8f-ae64-9be8c99ff663","key":"in-frame-pattern","name":"The -ิน Frame Repeats","shortDescription":"Once you know a syllable frame, swapping the first consonant unlocks more words","explanation":"กิน, บิน, and similar short words share the same short-i plus final-น frame. Thai gets much easier once you start seeing these reusable patterns instead of single isolated words.","examples":[{"text":"กิน = gin"},{"text":"บิน = bin"},{"text":"ดิน = din"}]}],"drills":[{"id":"52738597-5de3-55d7-a39c-34c088805b8d","key":"bin-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"b\" sound at the start?","payload":{},"options":[{"text":"บ","isCorrect":true},{"text":"ด"},{"text":"ม"},{"text":"น"}]},{"id":"524e2383-96d9-5f31-a5c1-4e4d5ae62344","key":"bin-drill-02-match","type":"match","prompt":"What does บิน mean?","payload":{},"options":[{"text":"to fly","isCorrect":true},{"text":"to eat"},{"text":"market"},{"text":"rice"}]},{"id":"2db2aeae-50e6-5409-ac53-a294a0bdec82","key":"bin-drill-03-spot","type":"spot","prompt":"Which Thai spelling means \"to fly\"?","payload":{},"options":[{"text":"บิน","isCorrect":true},{"text":"นบิ"},{"text":"บีน"},{"text":"ดิน"}]},{"id":"7946c7ee-41fe-5b34-acf3-07bd08891c89","key":"bin-drill-04-sound","type":"sound","prompt":"Which word keeps the same -ิน pattern as บิน?","payload":{},"options":[{"text":"กิน","isCorrect":true},{"text":"มาก"},{"text":"แม่"},{"text":"ร้าน"}]},{"id":"349b3282-167a-5e03-ac9d-dc39ff2c806f","key":"bin-drill-05-sound","type":"sound","prompt":"How do you pronounce บิน?","payload":{},"options":[{"text":"bin","isCorrect":true},{"text":"baan"},{"text":"boon"},{"text":"bii"}]}]}}'::jsonb, 'de8987534e055645ca5703e1fce12e57c708163e0326bb110b218306f4fdd580', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('03d24173-40f9-5857-a0f1-59c06a1edb43'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'dc5e9698-631e-5ce9-a0da-6c7fb1abd338'::uuid, 'maae', 6, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"dc5e9698-631e-5ce9-a0da-6c7fb1abd338","slug":"maae","lessonOrdinal":6,"stage":3,"title":"แม่ — Before Vowels and First Tone Marks","anchor":{"id":"89d521e3-4d9b-523d-ac4e-65377bfe9338","slug":"maae","text":"แม่","meaning":"mother","pronunciation":"mâae","categoryKey":"daily","contextNote":"You''ll see แม่ in family words, shop names, and cultural phrases. It also gives you your first look at a vowel written before the consonant.","segments":[{"text":"แม","sound":"mae"},{"text":"่","sound":"tone change"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"a23f7435-c081-54d4-abaa-0287352f280f","key":"word-0e41-0e01-0e48","text":"แก่","meaning":"old","pronunciation":"gae","categoryKey":"daily","segments":[{"text":"แก่","sound":"gae"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"1a4ba906-6b93-51e3-a976-f03034a08c69","key":"word-0e41-0e19-0e48","text":"แน่","meaning":"certain / sure","pronunciation":"nae","categoryKey":"daily","segments":[{"text":"แน่","sound":"nae"}],"metadata":{}}}],"newGraphemes":[{"id":"1684cb46-8524-51a4-ad84-8dd2fe3b46be","text":"แ","kind":"vowel","romanization":"ae","pronunciationHint":"long \"ae\" as in the vowel of \"care\"","mnemonic":"The doubled left-side shape sits in front of the consonant, warning you to scan left before you pronounce.","position":"left","details":{},"tags":[]},{"id":"13e7c7cd-283c-5d0b-a9cc-ce5b3831e495","text":"่","kind":"tone_mark","romanization":"mai ek","pronunciationHint":"first tone mark written above the consonant","mnemonic":"The short falling tick leans downward like a small tone reminder dropped above the syllable.","position":"above","details":{},"tags":[]}],"reviewGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"Two rounded humps make an easy M shape you can spot quickly in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"A tall trailing line stretches the sound to the right, just like the long vowel it marks.","position":"right","details":{},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"The small domed shape feels grounded and steady, like the reliable d sound at the start of ดี.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"The long upper stroke sits above the consonant and holds the sound a little longer.","position":"above","details":{},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"A compact hook feels clipped and firm, which matches the tight stop you hear at the end of มาก.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"The smooth loop ends softly, which matches the easy n sound it gives you in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"The tiny mark above is quick and short, just like the clipped i sound it signals.","position":"above","details":{},"tags":[]}],"rules":[{"id":"339f3a02-f34d-5263-a796-4d45cd2e4b7f","key":"before-vowels-left","name":"Some Vowels Sit on the Left","shortDescription":"The vowel แ is written before the consonant you pronounce first","explanation":"Thai does not always place vowels after the consonant. In แม่, your eye has to notice แ on the left, then come back to read ม with that vowel sound attached.","examples":[{"text":"แม = mae"},{"text":"แก่ = gàe"}]},{"id":"c360364a-3f7a-5b8d-a892-563359ef7e9e","key":"mai-ek-tone-mark","name":"Meet Your First Tone Mark","shortDescription":"Tone marks sit above the consonant and change the sound of the whole syllable","explanation":"You do not need the full tone system at once. Start by recognizing that ่ lives above the consonant and changes the word you say. High-frequency sight words make tone marks easier to remember than abstract charts.","examples":[{"text":"แม่ = mâae"},{"text":"แก่ = gàe"}]}],"drills":[{"id":"5bc9e17a-4a8a-51bb-a316-aa0a0aa74608","key":"maae-drill-01-recognize","type":"recognize","prompt":"Which vowel is written before the consonant?","payload":{},"options":[{"text":"แ","isCorrect":true},{"text":"า"},{"text":"ิ"},{"text":"ี"}]},{"id":"1b86c74a-d1ff-548e-a833-04ecf6f7c281","key":"maae-drill-02-recognize","type":"recognize","prompt":"Which mark is mai ek?","payload":{},"options":[{"text":"่","isCorrect":true},{"text":"้"},{"text":"แ"},{"text":"ั"}]},{"id":"5b514efd-9fe0-52b0-a98d-87af1c9de60c","key":"maae-drill-03-match","type":"match","prompt":"What does แม่ mean?","payload":{},"options":[{"text":"mother","isCorrect":true},{"text":"shop"},{"text":"road"},{"text":"fresh"}]},{"id":"f0776231-13a2-56ed-a053-5092778712f0","key":"maae-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"mother\"?","payload":{},"options":[{"text":"แม่","isCorrect":true},{"text":"แม"},{"text":"มา"},{"text":"แน"}]},{"id":"87008ac4-4fa4-5eda-a86a-fbd12791e726","key":"maae-drill-05-recognize","type":"recognize","prompt":"What changes when you add ่ above แม?","payload":{},"options":[{"text":"the vowel disappears"},{"text":"the tone changes","isCorrect":true},{"text":"the final consonant changes"},{"text":"the word becomes longer"}]}]}}'::jsonb, '0a9e645ad63590fd887196e507293419703ed918e7b09a02ea821093265d28e1', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('54ff1cc4-122f-5a46-a56b-ca7ba4b0bdf9'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '5f706588-560c-598f-ab7a-52a47ecb2015'::uuid, 'raan', 7, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"5f706588-560c-598f-ab7a-52a47ecb2015","slug":"raan","lessonOrdinal":7,"stage":3,"title":"ร้าน — The Word on Every Storefront","anchor":{"id":"c971805c-561a-5000-a9e8-846afac9e80b","slug":"raan","text":"ร้าน","meaning":"shop","pronunciation":"râan","categoryKey":"place","contextNote":"You''ll see ร้าน everywhere: ร้านกาแฟ, ร้านอาหาร, ร้านยา. Learning it early pays off on almost every street.","segments":[{"text":"ร้า","sound":"raa"},{"text":"น","sound":"n"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"e6d37e59-6bb8-562c-a4e7-46559bcd6800","key":"word-0e25-0e49-0e32-0e19","text":"ล้าน","meaning":"million","pronunciation":"laan","categoryKey":"sign","segments":[{"text":"ล้า","sound":"laa"},{"text":"น","sound":"n"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"8af6bfe1-3b05-5ada-a070-0cafba9b65be","key":"word-0e14-0e49-0e32-0e19","text":"ด้าน","meaning":"side / aspect","pronunciation":"daan","categoryKey":"sign","segments":[{"text":"ด้า","sound":"daa"},{"text":"น","sound":"n"}],"metadata":{}}}],"newGraphemes":[{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"The flowing curve looks like it wants to roll forward, which helps you remember its quick initial r sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"The heavier mark sits above the consonant like a second, stronger tone cue.","position":"above","details":{},"tags":[]}],"reviewGraphemes":[{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"The smooth loop ends softly, which matches the easy n sound it gives you in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"A tall trailing line stretches the sound to the right, just like the long vowel it marks.","position":"right","details":{},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"Two rounded humps make an easy M shape you can spot quickly in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"The small domed shape feels grounded and steady, like the reliable d sound at the start of ดี.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"The little turtle-like shape is compact and steady, which matches the plain unaspirated t sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"50ada581-79e7-5549-a9a8-77693569d9b8","text":"ล","kind":"consonant","romanization":"l","pronunciationHint":"l as in \"love\"","mnemonic":"The looping lower line gives you an easy L that opens up many market and place words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"1684cb46-8524-51a4-ad84-8dd2fe3b46be","text":"แ","kind":"vowel","romanization":"ae","pronunciationHint":"long \"ae\" as in the vowel of \"care\"","mnemonic":"The doubled left-side shape sits in front of the consonant, warning you to scan left before you pronounce.","position":"left","details":{},"tags":[]},{"id":"13e7c7cd-283c-5d0b-a9cc-ce5b3831e495","text":"่","kind":"tone_mark","romanization":"mai ek","pronunciationHint":"first tone mark written above the consonant","mnemonic":"The short falling tick leans downward like a small tone reminder dropped above the syllable.","position":"above","details":{},"tags":[]}],"rules":[{"id":"ba8c4da3-023b-5812-a6fb-0c09b52ce472","key":"initial-r-sound","name":"Initial ร Gives You R","shortDescription":"At the start of a syllable, ร is read as an r sound","explanation":"Thai ร has a few different jobs, but in ร้าน it is straightforward: it starts the word with an r sound before the tone mark and vowel shape do the rest of the work.","examples":[{"text":"รา = raa"},{"text":"ร้าน = râan"}]},{"id":"9d39de17-63e6-5cde-a43b-0d5655df93ec","key":"mai-tho-above","name":"Tone Marks Sit Above the Consonant","shortDescription":"Even when the vowel is on the right, the tone mark still sits above the main consonant","explanation":"In ร้าน, the long vowel า is on the right, but the tone mark ้ still sits above ร. Thai asks you to scan the whole syllable block, not just read from left to right.","examples":[{"text":"ร้า = râa"},{"text":"ร้าน = râan"}]}],"drills":[{"id":"7552ce0b-c30c-52bc-a88e-872c25d657d5","key":"raan-drill-01-recognize","type":"recognize","prompt":"Which letter starts with the \"r\" sound?","payload":{},"options":[{"text":"ร","isCorrect":true},{"text":"ล"},{"text":"น"},{"text":"ม"}]},{"id":"de5ad6bb-5b0c-5ede-a4f5-6266b4601f04","key":"raan-drill-02-recognize","type":"recognize","prompt":"Which mark is mai tho?","payload":{},"options":[{"text":"่"},{"text":"้","isCorrect":true},{"text":"ี"},{"text":"แ"}]},{"id":"565b7d5e-735f-5050-ad09-71fed55ac6a7","key":"raan-drill-03-match","type":"match","prompt":"What does ร้าน mean?","payload":{},"options":[{"text":"mother"},{"text":"shop","isCorrect":true},{"text":"ten"},{"text":"very"}]},{"id":"d7002b7d-1e35-5a0f-ae7e-e26a33f09a90","key":"raan-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"shop\"?","payload":{},"options":[{"text":"ร้าน","isCorrect":true},{"text":"ร่าน"},{"text":"ราน"},{"text":"น้าร"}]},{"id":"29a3d27f-d998-532c-abcd-12564e689931","key":"raan-drill-05-sound","type":"sound","prompt":"Where is the tone mark written in ร้าน?","payload":{},"options":[{"text":"under the consonant"},{"text":"above the consonant","isCorrect":true},{"text":"before the vowel"},{"text":"after the final consonant"}]}]}}'::jsonb, 'e64b35a9bdbb6388b445fb8f7264172b0fa78b5cc50f8d7c4c3cdd7c59c6c4f5', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('b54e0d58-84f8-5ea6-a75a-6e3fa02991c2'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'a85af404-45e0-50ae-a491-e082f54018a8'::uuid, 'chut', 8, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"a85af404-45e0-50ae-a491-e082f54018a8","slug":"chut","lessonOrdinal":8,"stage":4,"title":"ชุด — Short U in Menu Combos","anchor":{"id":"8888dcb4-b725-5c58-abe7-96cfcb8ab970","slug":"chut","text":"ชุด","meaning":"set / combo","pronunciation":"chút","categoryKey":"food","contextNote":"ชุด shows up in set menus, school uniforms, and clothing signs. On menus, it often means a fixed combo or meal set.","segments":[{"text":"ชุ","sound":"chu"},{"text":"ด","sound":"t"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"5cded218-1a29-5f43-aa86-0333a6b83802","key":"word-0e0a-0e32-0e21","text":"ชาม","meaning":"bowl","pronunciation":"chaam","categoryKey":"food","segments":[{"text":"ชาม","sound":"chaam"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"123734b3-b6f6-5e91-ad26-b556d9a700d8","key":"word-0e14-0e38","text":"ดุ","meaning":"fierce / strict","pronunciation":"du","categoryKey":"daily","segments":[{"text":"ดุ","sound":"du"}],"metadata":{}}}],"newGraphemes":[{"id":"9593d6a6-13bb-563d-a33d-b01dd74e3528","text":"ช","kind":"consonant","romanization":"ch","pronunciationHint":"ch as in \"check\"","mnemonic":"The open top and downward turn give ช a distinct profile that is easy to separate from ส once you have seen it a few times.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"a57ca296-4754-50f0-aad0-9856fff5c81d","text":"ุ","kind":"vowel","romanization":"u","pronunciationHint":"short \"u\" as in \"put\"","mnemonic":"The small mark tucked below the consonant keeps the sound short and tight.","position":"below","details":{},"tags":[]}],"reviewGraphemes":[{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"The small domed shape feels grounded and steady, like the reliable d sound at the start of ดี.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"The little turtle-like shape is compact and steady, which matches the plain unaspirated t sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"The smooth loop ends softly, which matches the easy n sound it gives you in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"The tiny mark above is quick and short, just like the clipped i sound it signals.","position":"above","details":{},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"A tall trailing line stretches the sound to the right, just like the long vowel it marks.","position":"right","details":{},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"The flowing curve looks like it wants to roll forward, which helps you remember its quick initial r sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"The heavier mark sits above the consonant like a second, stronger tone cue.","position":"above","details":{},"tags":[]}],"rules":[{"id":"215881f9-c7b2-522c-aaea-b676d1f481a5","key":"short-u-below","name":"Short ุ Sits Below","shortDescription":"The short u vowel is written below the consonant you pronounce first","explanation":"Thai keeps asking you to scan vertically. In ชุด, the consonant ช comes first and the short vowel ุ is tucked underneath, so you read chu before the final consonant closes the syllable.","examples":[{"text":"ชุ = chu"},{"text":"ชุด = chút"}]},{"id":"707d8403-783a-58bc-a40e-f63cb7a936d5","key":"dead-syllable-stop","name":"Short Vowels Feel Clipped in Closed Syllables","shortDescription":"A short vowel plus a final stop makes the whole word feel quick and closed","explanation":"ชุด feels short because the vowel is short and the final consonant is stopped. This clipped rhythm shows up in lots of practical Thai words on menus and signs.","examples":[{"text":"ชุด = chút"},{"text":"มุด = mút"}]}],"drills":[{"id":"3618386b-665b-5416-a461-d0ef90065f36","key":"chut-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"ch\" sound?","payload":{},"options":[{"text":"ช","isCorrect":true},{"text":"ส"},{"text":"บ"},{"text":"ร"}]},{"id":"d59be859-7c84-5a9e-a350-e26e03ab8e12","key":"chut-drill-02-recognize","type":"recognize","prompt":"Which vowel is written below the consonant?","payload":{},"options":[{"text":"ุ","isCorrect":true},{"text":"ิ"},{"text":"า"},{"text":"แ"}]},{"id":"477d26d8-9e21-5d7c-a3c0-a8424c722db5","key":"chut-drill-03-match","type":"match","prompt":"What does ชุด mean on a menu?","payload":{},"options":[{"text":"set / combo","isCorrect":true},{"text":"fresh"},{"text":"rice"},{"text":"to fly"}]},{"id":"6e35c2ec-6361-5a90-a52b-2b9af1fc07a5","key":"chut-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"set / combo\"?","payload":{},"options":[{"text":"ชุด","isCorrect":true},{"text":"ชาด"},{"text":"สด"},{"text":"ชดุ"}]},{"id":"f533d512-ef1d-59d1-a42b-a53b713e4eeb","key":"chut-drill-05-sound","type":"sound","prompt":"How does the final ด sound in ชุด?","payload":{},"options":[{"text":"d"},{"text":"t","isCorrect":true},{"text":"n"},{"text":"silent"}]}]}}'::jsonb, '573c74ba1d5406f781f9fd75c8d287736617dbb1cea2d206ab4ff9784846b1a4', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('3785d71c-3918-5276-ad7b-6f6d07fa48c9'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'fb4954f1-e326-56e2-a3d1-b4132b60e254'::uuid, 'sip', 9, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"fb4954f1-e326-56e2-a3d1-b4132b60e254","slug":"sip","lessonOrdinal":9,"stage":4,"title":"สิบ — Read Prices Faster","anchor":{"id":"c7f7eeee-be9c-59ec-a5ca-e993cf2d61c4","slug":"sip","text":"สิบ","meaning":"ten","pronunciation":"sìp","categoryKey":"sign","contextNote":"สิบ helps with prices, receipts, and quantity labels. Even one number word gives you real payoff in markets and transit.","segments":[{"text":"สิ","sound":"si"},{"text":"บ","sound":"p"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"31b16e27-441e-5276-aaeb-a285613b2142","key":"word-0e2a-0e34-0e19","text":"สิน","meaning":"goods / merchandise","pronunciation":"sin","categoryKey":"sign","segments":[{"text":"สิ","sound":"si"},{"text":"น","sound":"n"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"cc6952b1-247e-5295-a69b-5c101bbac32e","key":"word-0e2a-0e32-0e21","text":"สาม","meaning":"three","pronunciation":"saam","categoryKey":"sign","segments":[{"text":"สาม","sound":"saam"}],"metadata":{}}}],"newGraphemes":[{"id":"ae26196d-7a39-57e3-a8c4-061567bf9167","text":"ส","kind":"consonant","romanization":"s","pronunciationHint":"s as in \"sun\"","mnemonic":"The tall curve with a pointed finish feels sharp, which matches the crisp s sound at the start of words.","position":"standalone","details":{"class":"high"},"tags":[]}],"reviewGraphemes":[{"id":"dddb2e02-9aa3-5dde-a2ab-25524fc96559","text":"บ","kind":"consonant","romanization":"b/p","pronunciationHint":"b as in \"bat\" at the start; clipped p at the end","mnemonic":"The open bowl shape makes บ easy to spot at the start of short, useful words like บิน and บิล.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"The tiny mark above is quick and short, just like the clipped i sound it signals.","position":"above","details":{},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"The smooth loop ends softly, which matches the easy n sound it gives you in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"The small domed shape feels grounded and steady, like the reliable d sound at the start of ดี.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"9593d6a6-13bb-563d-a33d-b01dd74e3528","text":"ช","kind":"consonant","romanization":"ch","pronunciationHint":"ch as in \"check\"","mnemonic":"The open top and downward turn give ช a distinct profile that is easy to separate from ส once you have seen it a few times.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"a57ca296-4754-50f0-aad0-9856fff5c81d","text":"ุ","kind":"vowel","romanization":"u","pronunciationHint":"short \"u\" as in \"put\"","mnemonic":"The small mark tucked below the consonant keeps the sound short and tight.","position":"below","details":{},"tags":[]}],"rules":[{"id":"1a204ee8-b537-5026-a80e-84c60be7b87d","key":"initial-s-sound","name":"Initial ส Gives You S","shortDescription":"At the start of a syllable, ส is a clean s sound","explanation":"Thai has several letters that can map to an s-like sound, but you do not need them all at once. Start with ส because it appears constantly in useful words, labels, and polite formulas.","examples":[{"text":"สิบ = sìp"},{"text":"สด = sòt"}]},{"id":"a81aec16-221e-590d-a79d-ca348451a472","key":"final-b-to-p","name":"Final บ Closes as P","shortDescription":"At the end of a word, บ does not stay a full b sound","explanation":"Like several Thai final consonants, บ gets clipped at the end of a syllable. In สิบ, your lips close for p without the full released English b sound.","examples":[{"text":"สิบ = sìp"},{"text":"บัส = bát"}]}],"drills":[{"id":"acc21424-6128-5919-a890-2a2c4ac0c784","key":"sip-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"s\" sound?","payload":{},"options":[{"text":"ส","isCorrect":true},{"text":"ช"},{"text":"ร"},{"text":"บ"}]},{"id":"f12da006-4547-53fe-ac15-725c30c4746c","key":"sip-drill-02-match","type":"match","prompt":"What does สิบ mean?","payload":{},"options":[{"text":"rice"},{"text":"shop"},{"text":"ten","isCorrect":true},{"text":"mother"}]},{"id":"106c959c-12be-57d5-ae47-989845755e78","key":"sip-drill-03-sound","type":"sound","prompt":"Why does final บ in สิบ sound like p?","payload":{},"options":[{"text":"Thai drops all final consonants"},{"text":"final บ closes as p in Thai","isCorrect":true},{"text":"the tone mark changes it"},{"text":"the vowel makes it silent"}]},{"id":"02af70d4-c198-587f-aa33-3b8717f34737","key":"sip-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"ten\"?","payload":{},"options":[{"text":"สิบ","isCorrect":true},{"text":"บิส"},{"text":"สด"},{"text":"สบิ"}]},{"id":"df92c923-c1a1-513a-a6ab-ea02c5bf16df","key":"sip-drill-05-sound","type":"sound","prompt":"How do you pronounce สิบ?","payload":{},"options":[{"text":"sib"},{"text":"sii"},{"text":"sip","isCorrect":true},{"text":"sup"}]}]}}'::jsonb, '62af2779b2799abf404676bc16b6489b28d41492784c8087be37f1b53068ed56', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('a254cee8-2991-5cd1-aac1-883d929d4cd7'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '489857d0-a162-5afa-a7bb-c797b5761864'::uuid, 'khao', 10, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"489857d0-a162-5afa-a7bb-c797b5761864","slug":"khao","lessonOrdinal":10,"stage":5,"title":"ข้าว — A Survival Food Word","anchor":{"id":"cc47d33e-ee3d-50dc-a6ce-b3d61029996d","slug":"khao","text":"ข้าว","meaning":"rice","pronunciation":"khâao","categoryKey":"food","contextNote":"ข้าว is one of the highest-value food words in Thailand. It appears on menus, in meal names, and in everyday conversation.","segments":[{"text":"ข้า","sound":"khaa"},{"text":"ว","sound":"w glide"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"4b277ab9-99f9-523d-a6b3-895443e63944","key":"word-0e02-0e32-0e27","text":"ขาว","meaning":"white","pronunciation":"khaao","categoryKey":"daily","segments":[{"text":"ขาว","sound":"khaao"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"27f8a8b4-3ade-5533-a6bc-5a7bb7fdd7f4","key":"word-0e27-0e32-0e14","text":"วาด","meaning":"to draw","pronunciation":"waat","categoryKey":"daily","segments":[{"text":"วา","sound":"waa"},{"text":"ด","sound":"t"}],"metadata":{}}}],"newGraphemes":[{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"It looks like a more open cousin of ก, which helps you remember it is the airy high-class kh version.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"5e1b543b-6be0-5279-a812-4ec61ce2b1dc","text":"ว","kind":"consonant","romanization":"w","pronunciationHint":"w as in \"water\"; can help form vowel glides","mnemonic":"The curling shape feels like a small wave, which makes the w sound easy to picture.","position":"standalone","details":{"class":"low"},"tags":[]}],"reviewGraphemes":[{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"A tall trailing line stretches the sound to the right, just like the long vowel it marks.","position":"right","details":{},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"A compact hook feels clipped and firm, which matches the tight stop you hear at the end of มาก.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"Two rounded humps make an easy M shape you can spot quickly in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"The flowing curve looks like it wants to roll forward, which helps you remember its quick initial r sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"The heavier mark sits above the consonant like a second, stronger tone cue.","position":"above","details":{},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"The smooth loop ends softly, which matches the easy n sound it gives you in common words.","position":"standalone","details":{"class":"low"},"tags":[]}],"rules":[{"id":"71da4ee2-bbc8-5047-a6bf-bbfd13816bfc","key":"kh-vs-k","name":"ข Adds Air to K","shortDescription":"ข is not the same as ก; it has a stronger puff of air","explanation":"Thai distinguishes plain k sounds from aspirated kh sounds. If you hold your hand in front of your mouth, ข pushes out a little air in a way ก does not.","examples":[{"text":"กา = gaa"},{"text":"ขาว = khǎao"},{"text":"ข้าว = khâao"}]},{"id":"52b3fcea-a418-58db-ad81-2054c133fba1","key":"aaw-glide","name":"ว Can Help Build a Vowel Glide","shortDescription":"In words like ข้าว, ว helps shape the ending vowel sound instead of behaving like a full separate consonant","explanation":"Not every written consonant is heard as a clean standalone consonant. In ข้าว, ว helps form the -าว ending, so you hear a smooth glide rather than a sharp final w.","examples":[{"text":"ขาว = khǎao"},{"text":"ข้าว = khâao"}]}],"drills":[{"id":"9277e873-bfa3-53f7-a26f-72549d58727a","key":"khao-drill-01-recognize","type":"recognize","prompt":"Which letter gives the aspirated \"kh\" sound?","payload":{},"options":[{"text":"ก"},{"text":"ข","isCorrect":true},{"text":"บ"},{"text":"ห"}]},{"id":"72b362c6-5874-5eb5-ae33-d322cad13016","key":"khao-drill-02-recognize","type":"recognize","prompt":"Which letter helps build the -าว ending in ข้าว?","payload":{},"options":[{"text":"น"},{"text":"ว","isCorrect":true},{"text":"ร"},{"text":"ล"}]},{"id":"c744f172-4cd7-5f24-a563-6dbefb6498ad","key":"khao-drill-03-match","type":"match","prompt":"What does ข้าว mean?","payload":{},"options":[{"text":"rice","isCorrect":true},{"text":"fresh"},{"text":"ten"},{"text":"mother"}]},{"id":"a54b1113-2c41-5e38-a0a6-f4ed6ce3b6f3","key":"khao-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"rice\"?","payload":{},"options":[{"text":"ข้าว","isCorrect":true},{"text":"ขาว"},{"text":"ข้า"},{"text":"ขน"}]},{"id":"62a04a09-d6ca-5d0c-a968-c3a5a904b052","key":"khao-drill-05-sound","type":"sound","prompt":"What is the key difference between ก and ข?","payload":{},"options":[{"text":"ก is nasal and ข is silent"},{"text":"ข has a puff of air and ก does not","isCorrect":true},{"text":"they sound the same"},{"text":"ข is only used at the end of words"}]}]}}'::jsonb, '020c383f89b38cb1832c629145ef009f8058b6af619d9c466a4589936df6857d', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('a606d673-c171-56e5-a0a8-09a4dee06c2f'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '6a8b53e3-50a0-5db3-a089-a15c56bc01c6'::uuid, 'moo', 11, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"6a8b53e3-50a0-5db3-a089-a15c56bc01c6","slug":"moo","lessonOrdinal":11,"stage":5,"title":"หมู — Leading ห in a Real Menu Word","anchor":{"id":"c771541d-bc22-55d6-ade9-52b9d986cfe2","slug":"moo","text":"หมู","meaning":"pork","pronunciation":"mǔu","categoryKey":"food","contextNote":"หมู is everywhere on Thai menus. It is also the cleanest early example of the leading-ห pattern that learners need sooner rather than later.","segments":[{"text":"ห","sound":"leading h"},{"text":"มู","sound":"muu"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"8c79ebe5-9b38-5d70-a534-b40b909e194e","key":"word-0e2b-0e21-0e32","text":"หมา","meaning":"dog","pronunciation":"maa","categoryKey":"daily","segments":[{"text":"หมา","sound":"maa"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"8add2650-ea68-509f-ae3d-8c35db8b7b59","key":"word-0e2b-0e39","text":"หู","meaning":"ear","pronunciation":"huu","categoryKey":"daily","segments":[{"text":"หู","sound":"huu"}],"metadata":{}}}],"newGraphemes":[{"id":"98079396-6adf-5409-a63c-121764a3840e","text":"ห","kind":"consonant","romanization":"h","pronunciationHint":"h as in \"hello\"; often used as a leading tone helper","mnemonic":"The tall jar-like shape is easy to remember, and in many useful words it quietly sets up the tone of the consonant after it.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"6cbd6547-63c8-52cd-a2e5-378aa42e3e46","text":"ู","kind":"vowel","romanization":"uu","pronunciationHint":"long \"oo\" as in \"food\"","mnemonic":"The long lower loop hangs below the consonant and keeps the oo sound going.","position":"below","details":{},"tags":[]}],"reviewGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"Two rounded humps make an easy M shape you can spot quickly in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"It looks like a more open cousin of ก, which helps you remember it is the airy high-class kh version.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"A tall trailing line stretches the sound to the right, just like the long vowel it marks.","position":"right","details":{},"tags":[]},{"id":"5e1b543b-6be0-5279-a812-4ec61ce2b1dc","text":"ว","kind":"consonant","romanization":"w","pronunciationHint":"w as in \"water\"; can help form vowel glides","mnemonic":"The curling shape feels like a small wave, which makes the w sound easy to picture.","position":"standalone","details":{"class":"low"},"tags":[]}],"rules":[{"id":"62ade15b-2ecf-5726-a1dd-6689ff8c548e","key":"leading-h-pattern","name":"Leading ห Changes the Tone Pattern","shortDescription":"In common words like หมู, ห helps a following low consonant behave differently","explanation":"This is one of the Thai chunks worth learning as a whole. In words like หมู, the ห is not there to give you a full h sound before every letter. It helps control the syllable pattern of the low consonant that follows.","examples":[{"text":"หมู = mǔu"},{"text":"หมา = mǎa"}]},{"id":"d5b18e8e-9a1e-5ea5-a808-651961f8dfb4","key":"long-uu-below","name":"Long ู Sits Below","shortDescription":"The long oo vowel is written below the consonant","explanation":"Thai uses the space below the line too. In หมู and หู, the vowel ู sits under the consonant and gives you a long oo sound.","examples":[{"text":"หมู = mǔu"},{"text":"หู = hǔu"}]}],"drills":[{"id":"aee4f232-92da-5ff9-ab9a-4f6159e0013a","key":"moo-drill-01-recognize","type":"recognize","prompt":"Which letter is the leading ห in หมู?","payload":{},"options":[{"text":"ห","isCorrect":true},{"text":"ม"},{"text":"ข"},{"text":"อ"}]},{"id":"88afeac6-4549-51f2-a692-0619b08828d8","key":"moo-drill-02-recognize","type":"recognize","prompt":"Which vowel makes the long \"oo\" sound?","payload":{},"options":[{"text":"ุ"},{"text":"ู","isCorrect":true},{"text":"ิ"},{"text":"ี"}]},{"id":"8b2a3c3c-c41d-5097-afcd-6ae79c70b553","key":"moo-drill-03-match","type":"match","prompt":"What does หมู mean?","payload":{},"options":[{"text":"pork","isCorrect":true},{"text":"rice"},{"text":"shop"},{"text":"food"}]},{"id":"de1ce793-e310-5856-a6da-cabd69b2e3d9","key":"moo-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"pork\"?","payload":{},"options":[{"text":"หมู","isCorrect":true},{"text":"มู"},{"text":"หมา"},{"text":"ขู"}]},{"id":"81bb588d-fda4-5b93-ac8d-d7b10794035c","key":"moo-drill-05-sound","type":"sound","prompt":"Why is ห useful in words like หมู?","payload":{},"options":[{"text":"It adds a final consonant"},{"text":"It changes the tone pattern of the low consonant that follows","isCorrect":true},{"text":"It marks plural"},{"text":"It makes the vowel longer all by itself"}]}]}}'::jsonb, 'b2741ef5d97e9fc129c97e0f08958bec825490611fcf8900dd235a3f27e03410', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('96311bdb-d7ff-5120-a392-2a9046da278b'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'e387c914-ad75-5a7c-a972-cf079418042d'::uuid, 'ahan', 12, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"e387c914-ad75-5a7c-a972-cf079418042d","slug":"ahan","lessonOrdinal":12,"stage":5,"title":"อาหาร — Silent Carrier, Useful Sign","anchor":{"id":"01409ff0-7f6d-54f3-ab1e-8e428d0ca405","slug":"ahan","text":"อาหาร","meaning":"food","pronunciation":"aa-hǎan","categoryKey":"food","contextNote":"อาหาร appears on restaurant signs, food courts, and delivery labels. Once you can read ร้านอาหาร, the street starts feeling more legible.","segments":[{"text":"อา","sound":"aa"},{"text":"หา","sound":"hǎa"},{"text":"ร","sound":"n"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"ea2a12f2-2664-5e49-ab45-f5003a0c4702","key":"word-0e2d-0e48-0e32-0e19","text":"อ่าน","meaning":"to read","pronunciation":"aan","categoryKey":"sign","contextNote":"A high-payoff verb for menus, labels, and interface text once the silent carrier starts to click.","segments":[{"text":"อ่า","sound":"aa"},{"text":"น","sound":"n"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"c0ae7fff-a846-5198-af67-4174b5a833ab","key":"word-0e2d-0e2d-0e01","text":"ออก","meaning":"to exit / go out","pronunciation":"awk","categoryKey":"sign","contextNote":"A survival sign word that appears on doors, stations, and directional labels.","segments":[{"text":"ออ","sound":"aaw"},{"text":"ก","sound":"k"}],"metadata":{}}}],"newGraphemes":[{"id":"d6388a97-b0cb-5594-af90-48fd4c770e0f","text":"อ","kind":"consonant","romanization":"silent carrier","pronunciationHint":"placeholder consonant used when a syllable begins with a vowel sound","mnemonic":"The empty circle looks like an open placeholder, which is exactly what it does when Thai needs a consonant slot for a vowel.","position":"standalone","details":{"class":"mid"},"tags":[]}],"reviewGraphemes":[{"id":"98079396-6adf-5409-a63c-121764a3840e","text":"ห","kind":"consonant","romanization":"h","pronunciationHint":"h as in \"hello\"; often used as a leading tone helper","mnemonic":"The tall jar-like shape is easy to remember, and in many useful words it quietly sets up the tone of the consonant after it.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"The flowing curve looks like it wants to roll forward, which helps you remember its quick initial r sound.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"A tall trailing line stretches the sound to the right, just like the long vowel it marks.","position":"right","details":{},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"The small domed shape feels grounded and steady, like the reliable d sound at the start of ดี.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"The smooth loop ends softly, which matches the easy n sound it gives you in common words.","position":"standalone","details":{"class":"low"},"tags":[]}],"rules":[{"id":"12476104-aabd-52e5-ad0e-4994d23aec74","key":"silent-carrier","name":"อ Can Carry a Vowel Silently","shortDescription":"Thai still wants a consonant slot even when the syllable begins with a vowel sound","explanation":"In อาหาร, the first syllable sounds like aa, but Thai still writes a consonant letter to hold that opening vowel. อ acts as the carrier without adding a strong sound of its own.","examples":[{"text":"อา = aa"},{"text":"อาหาร = aa-hǎan"}]},{"id":"b144050a-1ef9-53f3-ae3c-d669fc4571f3","key":"final-r-to-n","name":"Final ร Often Sounds Like \"n\"","shortDescription":"At the end of a syllable, ร is often heard as \"n\" instead of a full r","explanation":"Thai final consonants do not always match their initial sounds. In อาหาร, the final ร is not read as a strong r. It closes the word with an n-like ending instead.","examples":[{"text":"อาหาร = aa-hǎan"},{"text":"สาร = sǎan"}]}],"drills":[{"id":"1b4dcf0d-6c4b-508e-a299-8c8d60f12f33","key":"ahan-drill-01-recognize","type":"recognize","prompt":"Which letter is the silent carrier?","payload":{},"options":[{"text":"อ","isCorrect":true},{"text":"ห"},{"text":"ร"},{"text":"ว"}]},{"id":"f802dbbd-32dc-5fc5-a3ec-03038e9fe5c8","key":"ahan-drill-02-match","type":"match","prompt":"What does อาหาร mean?","payload":{},"options":[{"text":"food","isCorrect":true},{"text":"set menu"},{"text":"mother"},{"text":"to fly"}]},{"id":"143f1ddd-6c90-53a5-aca3-03d10ecb8226","key":"ahan-drill-03-spot","type":"spot","prompt":"Which Thai spelling means \"food\"?","payload":{},"options":[{"text":"อาหาร","isCorrect":true},{"text":"หารอา"},{"text":"หมู"},{"text":"ผัด"}]},{"id":"afd544e1-be46-5ddc-a9bb-a97a33eee37a","key":"ahan-drill-04-sound","type":"sound","prompt":"How does the final ร sound in อาหาร?","payload":{},"options":[{"text":"r"},{"text":"l"},{"text":"n","isCorrect":true},{"text":"silent"}]},{"id":"b917b9b7-a124-51ac-a09a-ac2df18d12cd","key":"ahan-drill-05-recognize","type":"recognize","prompt":"Why does อาหาร begin with อ?","payload":{},"options":[{"text":"It marks plural"},{"text":"Thai needs a consonant slot, so อ carries the opening vowel","isCorrect":true},{"text":"It is only decorative"},{"text":"It always means the word is formal"}]}]}}'::jsonb, 'd1fdbf5cb8333e5abfbc3690314255cc8727d835c91518b1219fa9bb891b04de', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('f41342dd-6644-59cb-a627-4f879f99628e'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '227b7204-c818-5c7c-ad68-654e72285cd6'::uuid, 'phat', 13, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"227b7204-c818-5c7c-ad68-654e72285cd6","slug":"phat","lessonOrdinal":13,"stage":5,"title":"ผัด — Unlock Stir-Fry Words","anchor":{"id":"d2faba91-170e-5cef-ad0b-7f3a04ac6143","slug":"phat","text":"ผัด","meaning":"stir-fry","pronunciation":"phàt","categoryKey":"food","contextNote":"ผัด appears on some of the most common Thai dishes, from ผัดไทย to vegetable stir-fries. It is one of the highest-value cooking words you can learn.","segments":[{"text":"ผั","sound":"pha"},{"text":"ด","sound":"t"}]},"vocabulary":[{"roleKey":"support","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"b0c734f8-b446-5b48-ab6f-188e3678a636","key":"word-0e1c-0e31-0e01","text":"ผัก","meaning":"vegetables","pronunciation":"phak","categoryKey":"food","contextNote":"A very common menu word that reinforces the same ผั- opening as ผัด.","segments":[{"text":"ผั","sound":"pha"},{"text":"ก","sound":"k"}],"metadata":{}}},{"roleKey":"support","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"3495dbf5-31fa-5f25-a888-d60549f83efd","key":"word-0e01-0e31-0e19","text":"กัน","meaning":"together / to prevent","pronunciation":"gan","categoryKey":"daily","segments":[{"text":"กั","sound":"ga"},{"text":"น","sound":"n"}],"metadata":{}}}],"newGraphemes":[{"id":"da8975d2-f60a-59f9-a1d2-f55df44b6bfa","text":"ผ","kind":"consonant","romanization":"ph","pronunciationHint":"ph with a puff of air, like the start of \"photo\" without the f sound","mnemonic":"Its tall, open shape makes it feel like an airy cousin of บ, which helps you remember the aspirated ph sound.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"6655bad5-f432-5868-aa67-e7247253802f","text":"ั","kind":"vowel","romanization":"a","pronunciationHint":"short \"a\" as in \"cut\"","mnemonic":"The small cap above the consonant keeps the vowel short and quick.","position":"above","details":{},"tags":[]}],"reviewGraphemes":[{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"The small domed shape feels grounded and steady, like the reliable d sound at the start of ดี.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"The little turtle-like shape is compact and steady, which matches the plain unaspirated t sound.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"It looks like a more open cousin of ก, which helps you remember it is the airy high-class kh version.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"98079396-6adf-5409-a63c-121764a3840e","text":"ห","kind":"consonant","romanization":"h","pronunciationHint":"h as in \"hello\"; often used as a leading tone helper","mnemonic":"The tall jar-like shape is easy to remember, and in many useful words it quietly sets up the tone of the consonant after it.","position":"standalone","details":{"class":"high"},"tags":[]},{"id":"d6388a97-b0cb-5594-af90-48fd4c770e0f","text":"อ","kind":"consonant","romanization":"silent carrier","pronunciationHint":"placeholder consonant used when a syllable begins with a vowel sound","mnemonic":"The empty circle looks like an open placeholder, which is exactly what it does when Thai needs a consonant slot for a vowel.","position":"standalone","details":{"class":"mid"},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"Two rounded humps make an easy M shape you can spot quickly in common words.","position":"standalone","details":{"class":"low"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"A tall trailing line stretches the sound to the right, just like the long vowel it marks.","position":"right","details":{},"tags":[]}],"rules":[{"id":"a760feb3-b11d-5a48-aa4b-dfb7b7a0c055","key":"ph-vs-b","name":"ผ Gives You an Airy Ph Sound","shortDescription":"ผ is not the same as บ; it starts with a stronger puff of air","explanation":"Thai distinguishes plain b/p-like sounds from aspirated ph sounds. In ผัด, you can feel a burst of air at the start that you do not get with บ.","examples":[{"text":"ผัด = phàt"},{"text":"ผัก = phàk"}]},{"id":"80814a05-caf2-5ac2-afd4-5311e1cc970e","key":"short-a-above","name":"Short ั Sits Above","shortDescription":"The short a vowel is written above the consonant","explanation":"Thai uses a small mark above the consonant for the short a sound in words like ผัด. It is quicker and more clipped than the long right-side vowel า you learned earlier.","examples":[{"text":"ผัด = phàt"},{"text":"ผัก = phàk"}]}],"drills":[{"id":"62ec9ab5-e2a5-5a39-afa3-ecd5bb5329e4","key":"phat-drill-01-recognize","type":"recognize","prompt":"Which letter makes the aspirated \"ph\" sound?","payload":{},"options":[{"text":"ผ","isCorrect":true},{"text":"บ"},{"text":"ห"},{"text":"ข"}]},{"id":"9f452601-a03f-5cae-adc1-7dd3fa1f3114","key":"phat-drill-02-recognize","type":"recognize","prompt":"Which vowel gives the short \"a\" sound above the consonant?","payload":{},"options":[{"text":"ั","isCorrect":true},{"text":"า"},{"text":"แ"},{"text":"ุ"}]},{"id":"9439e02a-87e1-5211-a4e0-618142290f68","key":"phat-drill-03-match","type":"match","prompt":"What does ผัด mean?","payload":{},"options":[{"text":"stir-fry","isCorrect":true},{"text":"food court"},{"text":"shop"},{"text":"ten"}]},{"id":"d7f90549-40dd-5a16-a101-e7f33354bfaf","key":"phat-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"stir-fry\"?","payload":{},"options":[{"text":"ผัด","isCorrect":true},{"text":"ผาด"},{"text":"ผาก"},{"text":"ชุด"}]},{"id":"b9806e17-7198-5645-a174-7f5434e9b97c","key":"phat-drill-05-sound","type":"sound","prompt":"Which word shares the same ผั- opening as ผัด?","payload":{},"options":[{"text":"ผัก","isCorrect":true},{"text":"ข้าว"},{"text":"บิน"},{"text":"แม่"}]}]}}'::jsonb, '00b775396047bd1593c5ff736c4a9d91b73b84d63dba9c5f453efd15b92e0513', '2026-04-30T00:00:00+00:00'::timestamptz);

